#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
typedef double db;
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const long long INF=4e18;const int N=6e5+10;int x[N],y[N],num[N];
struct Node{long long Sin,Cos;inline bool operator == (const Node &x){return Sin==x.Sin&&Cos==x.Cos;}}a[N];
inline void Get(Node &Q,int x1,int y1,int x2,int y2,int x3,int y3)
	{int X1=(x2-x1),Y1=(y2-y1),X2=(x3-x1),Y2=(y3-y1);Q.Sin=(X1*Y2-X2*Y1);Q.Cos=(X1*X2+Y1*Y2);}
inline void Solve()
{
    memset(num,0,sizeof(num));
	int n=read();rep(1,n,i)x[i]=x[i+n]=x[i+2*n]=read(),y[i]=y[i+n]=y[i+2*n]=read();
	x[0]=x[n];x[3*n+1]=x[1];y[0]=y[n];y[3*n+1]=y[1];int m=0;a[++m].Sin=INF;
	int ans=0;rep(1,3*n,i)
	{
		Get(a[++m],x[i],y[i],x[i-1],y[i-1],x[i+1],y[i+1]);
		a[++m].Sin=INF;
	}
	int Mid=0,Mxn=0;rep(1,m,i)
	{
		num[i]=(i<Mxn)?min(num[Mid*2-i],Mxn-i):1;
		while(i+num[i]<=m&&i-num[i]>=1&&a[i+num[i]]==a[i-num[i]])++num[i];
		i+num[i]>Mxn?(Mxn=i+num[i],Mid=i):0;
	}
	rep(2*n+1,4*n,i)ans+=(num[i]>=n);
	printf("%d\n",ans>>1);
}
int main(){int T=read();while(T--)Solve();return 0;}
